-----------------------------------------------------------------
---闪避行为
-----------------------------------------------------------------
---@type LFightIdleBaseAction
local LFightIdleBaseAction = LXImport(".LFightIdleBaseAction")

---@class LFightIdleDogeAction:LFightIdleBaseAction
local LFightIdleDogeAction = LxClass("LFightIdleDogeAction",LFightIdleBaseAction)
-----------------------------------------------------------------
function LFightIdleDogeAction:LFightIdleDogeAction()
	self._action = LFightIdleConst.ACTION_DOGE

	self._nextDogeTime = -1
	self._dogeEndTime = 0
end
-----------------------------------------------------------------
function LFightIdleDogeAction:OnRun(time)
	if self._dogeEndTime <= time then
		self:ResetDefaultAction()
	end
end
-----------------------------------------------------------------

function LFightIdleDogeAction:ResetDefaultAction()
	if self._obj:SetStatus(LFightIdleConst.STATUS_DOGE) then
		self._obj:PlayIdleAni()
	end
	local ai = self._ai
	ai:ChangeAction(ai:GetDefaultAction())
end

-----------------------------------------------------------------
function LFightIdleDogeAction:StartAction()
	local nowTime = self:GetTime()-- Time.time

	local jumpTime = 0.3
	self._dogeEndTime = jumpTime + nowTime

	local obj = self._obj
	local jumpCd = obj:GetJumpCd()
	self._nextDogeTime = nowTime + jumpCd


	obj:StopActor()

	obj:SetStatus(LFightIdleConst.STATUS_DOGE)
	obj:PlayJumpAni(false)

	local nowPos = obj:GetPosition()
	local nowMinPos,nowMaxPos = obj:GetPathData()
	nowMinPos = nowMinPos or (nowPos + Vector3.New(-0.5,0,0))
	nowMaxPos = nowMaxPos or (nowPos + Vector3.New(0.5,0,0))

	local nowY = nowPos.y

	local nowX = nowPos.x
	local minX = nowMinPos.x
	local maxX = nowMaxPos.x

	local jumpDis = 1 -- 后跳距离
	local dogeDir = obj:GetDogeDir() --闪避方向
	local curDis = -jumpDis
	if dogeDir == LFightIdleConst.DIRECTION_RIGHT then -- 朝右边闪避
		curDis = jumpDis
	end
	if LFightIdleConst.Approximately(nowX,minX) then --最左边只能往右边跳
		curDis = jumpDis
	elseif LFightIdleConst.Approximately(nowX,maxX) then --最左边只能往左边跳
		curDis = -jumpDis
	end

	local moveX = nowX + curDis

	if moveX > maxX then
		moveX = maxX
	elseif moveX < minX then
		moveX = minX
	end

	local topY = nowY + 1
	local topX = Mathf.Lerp(nowX , moveX , 1 / 3)

	local moveActor = obj:GetMoveActor()
	moveActor:JumpTo(Vector3(moveX,nowY,0),Vector3(topX,topY,0),jumpTime)
end

-----------------------------------------------------------------
function LFightIdleDogeAction:StopAction()

end

function LFightIdleDogeAction:IsDogeReady()
	return self._nextDogeTime <= self:GetTime() --Time.time
end

function LFightIdleDogeAction:Destroy()

	LFightIdleBaseAction.Destroy(self)
end


return LFightIdleDogeAction